import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Use a StringBuilder to dynamically allocate memory for the user input
        StringBuilder buffer = new StringBuilder();

        // Copy user input into the dynamic buffer
        for (int i = 0; i < name.length() && i < 10; i++) {
            buffer.append(name.charAt(i));
        }

        System.out.println("Hello, " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
